import{_ as t,a,b as d,c as i}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as r,o,c as l,a2 as n}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"เพิ่ม WebDAV Channel","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/upload/webdav.md","filePath":"th-TH/upload/webdav.md","lastUpdated":1781962217000}'),s={name:"th-TH/upload/webdav.md"};function c(p,e,h,u,b,m){return o(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="เพิ่ม-webdav-channel" tabindex="-1">เพิ่ม WebDAV Channel <a class="header-anchor" href="#เพิ่ม-webdav-channel" aria-label="Permalink to &quot;เพิ่ม WebDAV Channel&quot;">​</a></h1><h2 id="เหมาะกับกรณีไหน" tabindex="-1">เหมาะกับกรณีไหน <a class="header-anchor" href="#เหมาะกับกรณีไหน" aria-label="Permalink to &quot;เหมาะกับกรณีไหน&quot;">​</a></h2><p>ใช้ WebDAV channel เมื่อ:</p><ul><li>คุณมี NAS, cloud drive หรือ object storage service ที่มี WebDAV endpoint</li><li>ต้องการให้ uploaded images ถูกเก็บใน WebDAV directory ของคุณเอง</li><li>ต้องการให้ credentials ถูกบันทึกใน D1 <code>upload_channels</code> table แทนการ expose ระยะยาวใน frontend</li></ul><h2 id="สิ่งที่ต้องเตรียมก่อนเริ่ม" tabindex="-1">สิ่งที่ต้องเตรียมก่อนเริ่ม <a class="header-anchor" href="#สิ่งที่ต้องเตรียมก่อนเริ่ม" aria-label="Permalink to &quot;สิ่งที่ต้องเตรียมก่อนเริ่ม&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>Server-side WebDAV URL เช่น <code>https://nas.example.com/dav</code></td></tr><tr><td>Username</td><td>ใช้ sign in เข้า WebDAV service</td></tr><tr><td>Password</td><td>ใช้ sign in เข้า WebDAV service</td></tr><tr><td>Authentication mode</td><td>ค่าเริ่มต้นคือ <code>Basic</code> ใช้ <code>Digest</code> หรือ auto negotiation เฉพาะเมื่อ server ต้องการ</td></tr><tr><td>Storage directory</td><td>Directory สำหรับเก็บ files ค่าเริ่มต้นคือ <code>imgbed</code></td></tr></tbody></table><h2 id="เพิ่มได้จากที่ไหน" tabindex="-1">เพิ่มได้จากที่ไหน <a class="header-anchor" href="#เพิ่มได้จากที่ไหน" aria-label="Permalink to &quot;เพิ่มได้จากที่ไหน&quot;">​</a></h2><ol><li>เปิด System Settings</li><li>ไปที่ Upload Settings</li><li>คลิก Add Channel ที่มุมขวาบน</li><li>เลือก <code>WebDAV</code></li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>ใช้ทำอะไร</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>ชื่อที่จำง่ายสำหรับ WebDAV channel เช่น <code>koofr</code> หรือ <code>nas</code></td><td>Yes</td></tr><tr><td>Endpoint</td><td>Full WebDAV endpoint รวม <code>https://</code></td><td>Yes</td></tr><tr><td>Username</td><td>WebDAV login username</td><td>Yes</td></tr><tr><td>Password</td><td>WebDAV login password</td><td>Yes</td></tr><tr><td>Authentication mode</td><td>โดยปกติใช้ <code>Basic</code>; ใช้ <code>Digest</code> หาก server ต้องการ digest authentication</td><td>Yes</td></tr><tr><td>Storage directory</td><td>Directory สำหรับเก็บ files ค่าเริ่มต้นคือ <code>imgbed</code></td><td>No</td></tr></tbody></table><h2 id="example-fie-nl-tab-digital" tabindex="-1">Example: fie.nl.tab.digital <a class="header-anchor" href="#example-fie-nl-tab-digital" aria-label="Permalink to &quot;Example: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-สร้าง-app-password" tabindex="-1">1. สร้าง App Password <a class="header-anchor" href="#_1-สร้าง-app-password" aria-label="Permalink to &quot;1. สร้าง App Password&quot;">​</a></h3><p>เปิด account security settings หา application passwords แล้วสร้าง app password ใหม่</p><p><img src="'+t+'" alt="Create an app password" loading="lazy"></p><p>หลังสร้างแล้วให้ copy และ save app password ใหม่ไว้ โดยปกติจะแสดงเพียงครั้งเดียว</p><p><img src="'+a+'" alt="Save the new app password" loading="lazy"></p><h3 id="_2-ใส่-webdav-configuration-ใน-imgbed" tabindex="-1">2. ใส่ WebDAV Configuration ใน ImgBed <a class="header-anchor" href="#_2-ใส่-webdav-configuration-ใน-imgbed" aria-label="Permalink to &quot;2. ใส่ WebDAV Configuration ใน ImgBed&quot;">​</a></h3><p>กลับไปที่ ImgBed แล้วเพิ่ม WebDAV channel:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Endpoint</td><td>WebDAV URL ที่ได้จาก <code>https://fie.nl.tab.digital/</code></td></tr><tr><td>Username</td><td>WebDAV username ของคุณ</td></tr><tr><td>Password</td><td>App password ที่เพิ่งสร้าง</td></tr><tr><td>Authentication mode</td><td>ส่วนใหญ่เริ่มด้วย <code>Basic</code></td></tr><tr><td>Storage directory</td><td>ค่าเริ่มต้นคือ <code>imgbed</code>; หรือใช้ custom directory ได้</td></tr></tbody></table><p><img src="'+d+'" alt="Fill in the configuration" loading="lazy"></p><h2 id="พฤติกรรมการ-upload-large-file" tabindex="-1">พฤติกรรมการ Upload Large File <a class="header-anchor" href="#พฤติกรรมการ-upload-large-file" aria-label="Permalink to &quot;พฤติกรรมการ Upload Large File&quot;">​</a></h2><p>WebDAV channel ตอนนี้ใช้ real session-based chunked upload</p><p>Small files จะถูก upload เป็น complete file ไฟล์เดียว Files ที่ใหญ่กว่า 64 MiB จะถูกแบ่งเป็น chunks ประมาณ 10 MiB อัตโนมัติ แล้ว upload ไปยัง remote chunk directory</p><p>WebDAV service ไม่จำเป็นต้องรองรับ <code>partial update</code> หรือ offset-based writes ImgBed จะไม่ merge chunks เป็น large file เดียวบน remote server แต่จะเก็บ chunk manifest และอ่าน chunks ตามลำดับเมื่อมี request file</p><p>ในทางปฏิบัติ:</p><table tabindex="0"><thead><tr><th>File Size</th><th>Upload Method</th><th>Remote Storage Layout</th></tr></thead><tbody><tr><td>64 MiB หรือน้อยกว่า</td><td>Normal upload</td><td>Complete file ไฟล์เดียว</td></tr><tr><td>มากกว่า 64 MiB</td><td>Real session chunked upload</td><td>Chunk directory ที่มีหลาย chunk files</td></tr></tbody></table><p>Chunk directory มีผลเฉพาะ remote storage layout ไม่เปลี่ยน file URL ใน ImgBed Users ยัง access file ผ่าน original <code>/file/...</code> link เหมือนเดิม</p><h2 id="ขั้นตอนตั้งค่า" tabindex="-1">ขั้นตอนตั้งค่า <a class="header-anchor" href="#ขั้นตอนตั้งค่า" aria-label="Permalink to &quot;ขั้นตอนตั้งค่า&quot;">​</a></h2><ol><li>เปิด Upload Settings</li><li>คลิก Add Channel</li><li>เลือก <code>WebDAV</code></li><li>ใส่ channel name ที่จำได้ เช่น <code>koofr</code></li><li>ใส่ WebDAV endpoint เช่น <code>https://app.koofr.net/dav/Koofr</code></li><li>ใส่ username และ password</li><li>ปล่อย authentication mode เป็น <code>Basic</code> เป็นค่าเริ่มต้น</li><li>ปล่อย storage directory เป็น <code>imgbed</code> หรือเปลี่ยนเป็น directory ของคุณเอง</li><li>คลิก Save</li><li>หลัง save ให้ตรวจ channel card, query capacity ถ้ามี และ upload test file</li></ol><h2 id="วิธีตรวจสอบ" tabindex="-1">วิธีตรวจสอบ <a class="header-anchor" href="#วิธีตรวจสอบ" aria-label="Permalink to &quot;วิธีตรวจสอบ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>วิธีตรวจสอบ</th></tr></thead><tbody><tr><td>เห็น channel card</td><td>หลัง save หน้า Upload Settings ควรแสดง WebDAV channel card</td></tr><tr><td>Channel enabled</td><td>Switch มุมขวาบนของ card ควรอยู่ on</td></tr><tr><td>Credentials ถูกบันทึก</td><td>Detail view ควรแสดง Endpoint, username, authentication mode และ storage directory</td></tr><tr><td>Small file upload ใช้งานได้</td><td>Upload test image แล้วตรวจว่า file อยู่ใน WebDAV directory</td></tr><tr><td>Large file rule ใช้งานได้</td><td>Files ใหญ่กว่า 64 MiB ใช้ chunked upload และสร้าง remote chunk directory</td></tr><tr><td>Capacity query ใช้งานได้</td><td>ถ้า server รองรับ capacity information query จะแสดง used และ total capacity</td></tr></tbody></table><p><img src="'+i+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="ทําไม-large-webdav-files-ถึงสร้าง-chunk-directory" tabindex="-1">ทำไม large WebDAV files ถึงสร้าง chunk directory? <a class="header-anchor" href="#ทําไม-large-webdav-files-ถึงสร้าง-chunk-directory" aria-label="Permalink to &quot;ทำไม large WebDAV files ถึงสร้าง chunk directory?&quot;">​</a></h3><p>นี่คือ storage method ปัจจุบันสำหรับ large files</p><p>Files ที่ใหญ่กว่า 64 MiB จะไม่ถูก merge เป็น remote file ขนาดใหญ่ไฟล์เดียว แต่จะเก็บเป็น chunk directory ImgBed บันทึก chunk manifest และคืน content ที่สมบูรณ์โดยอ่าน chunks ตามลำดับ</p><h3 id="large-file-upload-fail-ควรตรวจอะไรก่อน" tabindex="-1">Large file upload fail ควรตรวจอะไรก่อน? <a class="header-anchor" href="#large-file-upload-fail-ควรตรวจอะไรก่อน" aria-label="Permalink to &quot;Large file upload fail ควรตรวจอะไรก่อน?&quot;">​</a></h3><p>ตรวจ Endpoint, username, password และ storage directory ก่อน จากนั้น confirm ว่า WebDAV service อนุญาต directory creation, file writing และ file reading</p><p>ถ้า capacity query fail แต่ small file upload ใช้งานได้ server อาจไม่รองรับหรือจำกัด capacity reporting ไม่ได้แปลว่า upload ใช้งานไม่ได้</p><h3 id="ควรใช้-authentication-mode-ไหน" tabindex="-1">ควรใช้ authentication mode ไหน? <a class="header-anchor" href="#ควรใช้-authentication-mode-ไหน" aria-label="Permalink to &quot;ควรใช้ authentication mode ไหน?&quot;">​</a></h3><p>เริ่มจาก <code>Basic</code></p><p>ถ้า server ระบุว่าต้องใช้ digest authentication ให้ใช้ <code>Digest</code></p><p>ถ้าไม่แน่ใจ ใช้ automatic negotiation</p><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>เตรียม WebDAV endpoint, username และ password</span></span>
<span class="line"><span>-&gt; เปิด Upload Settings</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; เลือก WebDAV</span></span>
<span class="line"><span>-&gt; ใส่ Endpoint / username / password</span></span>
<span class="line"><span>-&gt; ปล่อย authentication mode เป็น Basic</span></span>
<span class="line"><span>-&gt; ปล่อย storage directory เป็น imgbed</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Query capacity</span></span>
<span class="line"><span>-&gt; Upload test file</span></span></code></pre></div>`,45)])])}const k=r(s,[["render",c]]);export{y as __pageData,k as default};
